-- =============================================================
-- FAKE / MOCK DATA cho Marketing Analytics Dashboard (Facebook Ads)
-- Khop CHINH XAC voi 6 file DDL that: 001..006_*.sql (da doi chieu ten bang/cot)
-- Muc dich: test hien thi bao cao end-to-end qua ca 3 tang
--           raw_events (grain = 1 account x 1 ngay) -> staging_ad_metrics -> fact_ad_metrics
-- An toan chay lai nhieu lan: xoa du lieu demo cu (theo account_external_id) truoc khi insert lai.
-- =============================================================

BEGIN;

-- 0) Don dep du lieu demo cu (neu chay lai script nay) — chi xoa du lieu cua account demo,
--    khong dung cascade de tranh xoa nham du lieu that neu trung external_id.
DELETE FROM fact_ad_metrics
WHERE ad_id IN (
  SELECT ad.ad_id FROM dim_ad ad
  JOIN dim_ad_set s ON s.ad_set_id = ad.ad_set_id
  JOIN dim_campaign c ON c.campaign_id = s.campaign_id
  JOIN dim_account acc ON acc.account_id = c.account_id
  WHERE acc.external_id = 'act_987654321000123'
);
DELETE FROM staging_ad_metrics WHERE account_external_id = 'act_987654321000123';
DELETE FROM raw_events WHERE account_external_id = 'act_987654321000123';

-- 1) dim_platform (idempotent, phong truong hop chua chay 006_seed_platforms.sql)
INSERT INTO dim_platform (platform_code, platform_name) VALUES
  ('FACEBOOK', 'Facebook Ads')
ON CONFLICT (platform_code) DO NOTHING;

-- 2) dim_account
INSERT INTO dim_account (platform_id, external_id, account_name)
SELECT platform_id, 'act_987654321000123', 'CleanFlow Demo Ad Account'
FROM dim_platform WHERE platform_code = 'FACEBOOK'
ON CONFLICT (platform_id, external_id) DO NOTHING;

-- 3) dim_campaign (chi co cot objective/status — dung objective/status that cua bang)
INSERT INTO dim_campaign (account_id, external_id, campaign_name, objective, status)
SELECT a.account_id, v.external_id, v.campaign_name, v.objective, v.status
FROM dim_account a, (VALUES
  ('1200000000001', 'FB_KhoaHocTiengAnh_T7_2026', 'CONVERSIONS', 'Normal'),
  ('1200000000002', 'FB_BaoHiemNhanTho_LeadGen_T7', 'LEAD_GENERATION', 'Cut-Off'),
  ('1200000000003', 'FB_KhoaHocTinHoc_Retarget_T7', 'TRAFFIC', 'Normal')
) AS v(external_id, campaign_name, objective, status)
WHERE a.external_id = 'act_987654321000123'
ON CONFLICT (account_id, external_id) DO NOTHING;

-- 4) dim_ad_set
-- LUU Y: dim_campaign that KHONG co cot Team/Product/Industry/Content Group/Month by campaign.
-- Toan bo 10 dimension mo rong ma 02-FRONTEND-SPEC.md muc 0 liet ke duoc gom vao
-- targeting_meta JSONB cua dim_ad_set (cot nay co san trong DDL that). Day la lua chon
-- hop ly nhat voi schema hien tai, nhung VAN CAN team xac nhan lai truoc khi Cline code that.
INSERT INTO dim_ad_set (campaign_id, external_id, ad_set_name, targeting_meta)
SELECT c.campaign_id, v.external_id, v.ad_set_name, v.targeting_meta::jsonb
FROM dim_campaign c, (VALUES
  ('1200000000001', '2300000000001', 'FB_KhoaHocTiengAnh_T7_2026_AdSet1', '{"team": 1, "team_type": "Sale Truc Tiep", "keymess": "Uu dai thang 7", "content_group": "Content Group A", "content_code": "CC-0001-01", "getback": "Khong getback", "product": "Khoa hoc Tieng Anh", "industry": "Giao duc", "sale_team": "Sale A", "month_by_campaign": "2026-07"}'),
  ('1200000000001', '2300000000002', 'FB_KhoaHocTiengAnh_T7_2026_AdSet2', '{"team": 1, "team_type": "Sale Truc Tiep", "keymess": "Uu dai thang 7", "content_group": "Content Group A", "content_code": "CC-0001-02", "getback": "Co getback", "product": "Khoa hoc Tieng Anh", "industry": "Giao duc", "sale_team": "Sale C", "month_by_campaign": "2026-07"}'),
  ('1200000000002', '2300000000003', 'FB_BaoHiemNhanTho_LeadGen_T7_AdSet1', '{"team": 2, "team_type": "Sale Truc Tiep", "keymess": "Tu van mien phi", "content_group": "Content Group B", "content_code": "CC-0002-01", "getback": "Khong getback", "product": "Bao hiem Nhan tho", "industry": "Tai chinh - Bao hiem", "sale_team": "Sale A", "month_by_campaign": "2026-07"}'),
  ('1200000000002', '2300000000004', 'FB_BaoHiemNhanTho_LeadGen_T7_AdSet2', '{"team": 2, "team_type": "Sale Truc Tiep", "keymess": "Uu dai thang 7", "content_group": "Content Group B", "content_code": "CC-0002-02", "getback": "Co getback", "product": "Bao hiem Nhan tho", "industry": "Tai chinh - Bao hiem", "sale_team": "Sale A", "month_by_campaign": "2026-07"}'),
  ('1200000000003', '2300000000005', 'FB_KhoaHocTinHoc_Retarget_T7_AdSet1', '{"team": 1, "team_type": "Sale Truc Tiep", "keymess": "Tu van mien phi", "content_group": "Content Group C", "content_code": "CC-0003-01", "getback": "Co getback", "product": "Khoa hoc Tin hoc", "industry": "Giao duc", "sale_team": "Sale C", "month_by_campaign": "2026-07"}'),
  ('1200000000003', '2300000000006', 'FB_KhoaHocTinHoc_Retarget_T7_AdSet2', '{"team": 1, "team_type": "Sale Online", "keymess": "Uu dai thang 7", "content_group": "Content Group C", "content_code": "CC-0003-02", "getback": "Khong getback", "product": "Khoa hoc Tin hoc", "industry": "Giao duc", "sale_team": "Sale C", "month_by_campaign": "2026-07"}')
) AS v(campaign_external_id, external_id, ad_set_name, targeting_meta)
WHERE c.external_id = v.campaign_external_id
ON CONFLICT (campaign_id, external_id) DO NOTHING;

-- 5) dim_ad
INSERT INTO dim_ad (ad_set_id, external_id, ad_name)
SELECT s.ad_set_id, v.external_id, v.ad_name
FROM dim_ad_set s, (VALUES
  ('2300000000001', '3400000000001', 'FB_KhoaHocTiengAnh_T7_2026_AdSet1_Ad1'),
  ('2300000000001', '3400000000002', 'FB_KhoaHocTiengAnh_T7_2026_AdSet1_Ad2'),
  ('2300000000002', '3400000000003', 'FB_KhoaHocTiengAnh_T7_2026_AdSet2_Ad1'),
  ('2300000000002', '3400000000004', 'FB_KhoaHocTiengAnh_T7_2026_AdSet2_Ad2'),
  ('2300000000003', '3400000000005', 'FB_BaoHiemNhanTho_LeadGen_T7_AdSet1_Ad1'),
  ('2300000000003', '3400000000006', 'FB_BaoHiemNhanTho_LeadGen_T7_AdSet1_Ad2'),
  ('2300000000004', '3400000000007', 'FB_BaoHiemNhanTho_LeadGen_T7_AdSet2_Ad1'),
  ('2300000000004', '3400000000008', 'FB_BaoHiemNhanTho_LeadGen_T7_AdSet2_Ad2'),
  ('2300000000005', '3400000000009', 'FB_KhoaHocTinHoc_Retarget_T7_AdSet1_Ad1'),
  ('2300000000005', '3400000000010', 'FB_KhoaHocTinHoc_Retarget_T7_AdSet1_Ad2'),
  ('2300000000006', '3400000000011', 'FB_KhoaHocTinHoc_Retarget_T7_AdSet2_Ad1'),
  ('2300000000006', '3400000000012', 'FB_KhoaHocTinHoc_Retarget_T7_AdSet2_Ad2')
) AS v(ad_set_external_id, external_id, ad_name)
WHERE s.external_id = v.ad_set_external_id
ON CONFLICT (ad_set_id, external_id) DO NOTHING;

